// Configure your sources here
const sources = [
  // { type: 'rss', name: 'App Store Reviews', url: 'https://rss.applemarketingtools.com/api/v2/us/apps/YOUR_APP_ID/reviews/most-recent.rss' },
  // { type: 'rss', name: 'Product Hunt', url: 'https://www.producthunt.com/feed?q=YOUR_PRODUCT' },
  // { type: 'rss', name: 'Reddit', url: 'https://www.reddit.com/r/YOUR_SUBREDDIT/new/.rss' },
  {
    type: 'sample',
    name: 'Sample Reviews (Testing)',
    items: [
      { text: 'The new dashboard is much faster. Loving the update!', source: 'app_store', url: 'https://example.com/review/1', date: new Date().toISOString().slice(0,10) },
      { text: 'Keeps crashing when I try to export to CSV. Very frustrating.', source: 'google_play', url: 'https://example.com/review/2', date: new Date().toISOString().slice(0,10) },
      { text: 'Competitor X just released a bulk import feature that we desperately need here too', source: 'reddit', url: 'https://example.com/review/3', date: new Date().toISOString().slice(0,10) },
    ]
  }
];
const allItems = [];
for (const src of sources) {
  if (src.type === 'sample') { allItems.push(...src.items); }
  // Add RSS parsing here if needed
}
return allItems.map(item => ({ json: item }));

